import React, { useState, useEffect } from 'react';
import { Menu, X } from 'lucide-react';

interface NavbarProps {
  isScrolled: boolean;
}

const Navbar: React.FC<NavbarProps> = ({ isScrolled }) => {
  const [isOpen, setIsOpen] = useState(false);

  const navLinks = [
    { name: 'Home', href: '#home' },
    { name: 'About', href: '#about' },
    { name: 'Products', href: '#products' },
    { name: 'Contact', href: '#contact' },
  ];

  const handleLinkClick = (e: React.MouseEvent<HTMLAnchorElement>, href: string) => {
    e.preventDefault();
    const targetId = href.replace('#', '');
    const element = document.getElementById(targetId);
    if (element) {
      setIsOpen(false);
      window.scrollTo({
        top: element.offsetTop - 80,
        behavior: 'smooth'
      });
    }
  };

  return (
    <nav className={`fixed top-0 w-full z-50 transition-all duration-300 ${
      isScrolled || isOpen ? 'bg-white shadow-md py-3' : 'bg-transparent py-5'
    }`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className={`w-10 h-10 flex items-center justify-center rounded-lg transition-colors ${
              isScrolled || isOpen ? 'bg-blue-600 text-white' : 'bg-white/10 backdrop-blur-sm text-blue-500'
            }`}>
              <svg viewBox="0 0 100 100" className="w-8 h-8 fill-current">
                 <path d="M20 50 Q35 20 50 50 T80 50" stroke="currentColor" strokeWidth="8" fill="none" />
                 <path d="M20 65 Q35 35 50 65 T80 65" stroke="currentColor" strokeWidth="8" fill="none" opacity="0.6" />
              </svg>
            </div>
            <span className={`text-xl font-bold tracking-tight transition-colors ${
              isScrolled || isOpen ? 'text-slate-900' : 'text-white'
            }`}>Flow Energy</span>
          </div>

          {/* Desktop Links */}
          <div className="hidden md:flex items-center space-x-8">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.href}
                onClick={(e) => handleLinkClick(e, link.href)}
                className={`text-sm font-semibold transition-colors hover:text-blue-500 ${
                  isScrolled ? 'text-slate-600' : 'text-white/90'
                }`}
              >
                {link.name}
              </a>
            ))}
            <a 
              href="#contact"
              onClick={(e) => handleLinkClick(e, '#contact')}
              className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-full text-sm font-bold transition-all shadow-lg shadow-blue-500/20 active:scale-95"
            >
              Get Quote
            </a>
          </div>

          {/* Mobile Menu Button */}
          <div className="md:hidden">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className={isScrolled || isOpen ? 'text-slate-900' : 'text-white'}
            >
              {isOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden fixed inset-x-0 top-[64px] bg-white shadow-2xl animate-in fade-in slide-in-from-top-4 h-screen z-50">
          <div className="px-6 pt-10 pb-20 space-y-6">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.href}
                onClick={(e) => handleLinkClick(e, link.href)}
                className="block text-2xl font-bold text-slate-800 hover:text-blue-600 transition-colors border-b border-slate-100 pb-4"
              >
                {link.name}
              </a>
            ))}
            <a 
              href="#contact"
              onClick={(e) => handleLinkClick(e, '#contact')}
              className="block w-full text-center bg-blue-600 text-white py-4 rounded-2xl text-lg font-bold mt-10 shadow-xl shadow-blue-600/20"
            >
              Get Quick Quote
            </a>
          </div>
        </div>
      )}
    </nav>
  );
};

