    if (sessionRef.current) {
      try {
        sessionRef.current.close();
      } catch (e) {
        console.error('Error closing session:', e);
      }
      sessionRef.current = null;
    }

    sourcesRef.current.forEach(source => {
      try {
        source.stop();
      } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setIsVoiceActive(false);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100] flex flex-col items-end">
      {isOpen && (
        <div className="bg-white w-[380px] h-[550px] mb-4 rounded-3xl shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-in fade-in slide-in-from-bottom-8">
          {/* Header */}
          <div className="p-5 bg-slate-900 text-white flex justify-between items-center shadow-lg">
            <div className="flex items-center space-x-3">
              <div className="w-10 h-10 rounded-xl bg-blue-600 flex items-center justify-center">
                <MessageSquare className="w-5 h-5 text-white" />
              </div>
              <div>
                <h4 className="font-bold text-sm">Flow Energy AI</h4>
                <div className="flex items-center space-x-1">
                  <span className={`w-2 h-2 rounded-full ${isVoiceActive ? 'bg-blue-400 animate-pulse' : 'bg-green-500'}`}></span>
                  <span className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">
                    {isVoiceActive ? 'Voice Active' : 'Online'}
                  </span>
                </div>
              </div>
            </div>
            <button onClick={() => { stopVoiceSession(); setIsOpen(false); }} className="hover:bg-white/10 p-1.5 rounded-lg transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>

          {/* Body: Chat Message List */}
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-4 bg-slate-50/50">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
                <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm leading-relaxed ${
                  m.role === 'user' 
                    ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/10 rounded-br-none' 
                    : 'bg-white text-slate-700 border border-slate-200 shadow-sm rounded-bl-none'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isLoading && !isVoiceActive && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-200 px-4 py-3 rounded-2xl">
                  <Loader2 className="w-4 h-4 text-blue-600 animate-spin" />
                </div>
              </div>
            )}
            {isVoiceActive && (
              <div className="flex flex-col items-center justify-center py-4 space-y-3 bg-blue-50/50 rounded-2xl border border-blue-100 border-dashed animate-pulse">
                <div className="w-10 h-10 bg-blue-600 rounded-full flex items-center justify-center text-white">
                  <Volume2 className="w-5 h-5" />
                </div>
                <p className="text-[10px] font-black uppercase text-blue-600 tracking-widest">Listening & Transcribing...</p>
              </div>
            )}
          </div>

          {/* Footer Input for Unified Chat & Voice */}
          <div className="p-4 bg-white border-t border-slate-100 space-y-3">
            <div className="flex items-center space-x-2">
              <button 
                onClick={startVoiceSession}
                className={`p-3 rounded-2xl transition-all shadow-lg active:scale-90 flex-shrink-0 ${
                  isVoiceActive 
                    ? 'bg-red-500 text-white animate-pulse' 
                    : 'bg-slate-100 text-slate-500 hover:bg-blue-50 hover:text-blue-600'
                }`}
                title={isVoiceActive ? "Stop Voice Mode" : "Start Voice Mode"}
              >
                {isVoiceActive ? <MicOff className="w-5 h-5" /> : <Mic className="w-5 h-5" />}
              </button>

              <div className="flex-1 flex items-center bg-slate-50 px-3 py-2 rounded-2xl border border-slate-200 focus-within:border-blue-500 focus-within:ring-2 focus-within:ring-blue-500/10 transition-all">
                <input 
                  type="text" 
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                  placeholder={isVoiceActive ? "Speak or type here..." : "Ask a question..."}
                  className="flex-1 bg-transparent text-sm px-2 focus:outline-none"
                />
                <button 
                  onClick={handleSend}
                  disabled={isLoading || !input.trim()}
                  className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-700 transition-colors disabled:opacity-30 disabled:scale-95"
                >
                  <Send className="w-4 h-4" />
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Main Floating Button */}
      <button 
        onClick={() => {
          if (isOpen && isVoiceActive) stopVoiceSession();
          setIsOpen(!isOpen);
        }}
        className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all duration-300 hover:scale-110 active:scale-95 group ${
          isOpen ? 'bg-slate-900 text-white' : 'bg-blue-600 text-white'
        }`}
      >
        {isOpen ? <X /> : <MessageSquare className="group-hover:animate-bounce" />}
        {!isOpen && (
          <span className="absolute right-16 bg-white border border-slate-200 text-slate-900 px-4 py-2 rounded-xl text-sm font-bold whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity shadow-lg pointer-events-none">
            How can I help?
          </span>
        )}
      </button>
    </div>
  );
};

